"use client";

import { useState, useCallback, useMemo } from "react";
import { StateData, Election } from "@/lib/types";
import {
  getStateCodesForZip,
  getStateData,
  findNextElection,
} from "@/lib/stateData";
import { buildPrompt } from "@/lib/promptBuilder";
import ZipForm from "./ZipForm";
import StateInfo from "./StateInfo";
import StateSelector from "./StateSelector";
import PromptOutput from "./PromptOutput";

type AppState =
  | { status: "idle" }
  | { status: "loading" }
  | { status: "multi-state"; zipCode: string; stateCodes: string[] }
  | {
      status: "result";
      zipCode: string;
      stateData: StateData;
      election: Election | null;
      promptText: string;
    }
  | { status: "not-found"; zipCode: string };

export default function BallotTool() {
  const [appState, setAppState] = useState<AppState>({ status: "idle" });
  const today = useMemo(() => new Date(), []);

  const handleZipSubmit = useCallback(
    (zipCode: string) => {
      setAppState({ status: "loading" });

      // Simulate minimal async (prevents layout shift, per PROJECT_SPEC.md)
      setTimeout(() => {
        const stateCodes = getStateCodesForZip(zipCode);

        if (stateCodes.length === 0) {
          setAppState({ status: "not-found", zipCode });
          return;
        }

        if (stateCodes.length > 1) {
          setAppState({ status: "multi-state", zipCode, stateCodes });
          return;
        }

        const stateCode = stateCodes[0];
        const data = getStateData(stateCode);

        if (!data) {
          setAppState({ status: "not-found", zipCode });
          return;
        }

        const election = findNextElection(data.elections, today);
        const promptText = buildPrompt(data, zipCode, election);

        setAppState({
          status: "result",
          zipCode,
          stateData: data,
          election,
          promptText,
        });
      }, 150);
    },
    [today],
  );

  const handleStateSelect = useCallback(
    (stateCode: string) => {
      if (appState.status !== "multi-state") return;
      const { zipCode } = appState;

      const data = getStateData(stateCode);
      if (!data) {
        setAppState({ status: "not-found", zipCode });
        return;
      }

      const election = findNextElection(data.elections, today);
      const promptText = buildPrompt(data, zipCode, election);

      setAppState({
        status: "result",
        zipCode,
        stateData: data,
        election,
        promptText,
      });
    },
    [appState, today],
  );

  return (
    <div className="w-full max-w-2xl mx-auto space-y-8">
      {/* Zip Code Entry */}
      <section aria-label="Zip code entry">
        <ZipForm
          onSubmit={handleZipSubmit}
          isLoading={appState.status === "loading"}
        />
      </section>

      {/* Loading indicator */}
      {appState.status === "loading" && (
        <div
          role="status"
          aria-live="polite"
          aria-label="Looking up your zip code"
          className="flex items-center gap-3 text-gray-600"
        >
          <svg
            className="w-5 h-5 animate-spin text-blue-600"
            fill="none"
            viewBox="0 0 24 24"
            aria-hidden="true"
          >
            <circle
              className="opacity-25"
              cx="12"
              cy="12"
              r="10"
              stroke="currentColor"
              strokeWidth="4"
            />
            <path
              className="opacity-75"
              fill="currentColor"
              d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"
            />
          </svg>
          <span>Looking up your zip code...</span>
        </div>
      )}

      {/* Not found */}
      {appState.status === "not-found" && (
        <div
          data-testid="not-found-message"
          role="alert"
          aria-live="polite"
          className="bg-amber-50 border border-amber-200 rounded-xl p-5 text-amber-800"
        >
          <h3 className="font-semibold text-base mb-1">Zip code not found</h3>
          <p className="text-sm">
            We don&apos;t have data for zip code{" "}
            <strong>{appState.zipCode}</strong> yet. We&apos;re working on
            adding all U.S. zip codes.{" "}
            <a
              href="https://www.usa.gov/state-election-office"
              target="_blank"
              rel="noopener noreferrer"
              className="underline hover:text-amber-900"
            >
              Find your state election website
            </a>
            .
          </p>
        </div>
      )}

      {/* Multi-state selector */}
      {appState.status === "multi-state" && (
        <StateSelector
          stateCodes={appState.stateCodes}
          selectedState={null}
          onSelect={handleStateSelect}
        />
      )}

      {/* Results */}
      {appState.status === "result" && (
        <>
          <StateInfo
            stateData={appState.stateData}
            election={appState.election}
            today={today}
            registrationCheckUrl={
              appState.stateData.registration.registrationCheckUrl
            }
          />
          <PromptOutput promptText={appState.promptText} />
        </>
      )}
    </div>
  );
}

"use client";

import { DeadlineStatus as StatusEnum } from "@/lib/types";
import {
  getDeadlineStatus,
  getDeadlineLabel,
  formatDate,
} from "@/lib/deadlineUtils";

interface DeadlineStatusProps {
  label: string;
  isoDate: string | null;
  today: Date;
  additionalInfo?: string;
}

const statusConfig: Record<
  StatusEnum,
  { textColor: string; bgColor: string; borderColor: string; label: string }
> = {
  [StatusEnum.GREEN]: {
    textColor: "text-green-800",
    bgColor: "bg-green-50",
    borderColor: "border-green-200",
    label: "Open",
  },
  [StatusEnum.YELLOW]: {
    textColor: "text-yellow-800",
    bgColor: "bg-yellow-50",
    borderColor: "border-yellow-200",
    label: "Closing Soon",
  },
  [StatusEnum.RED]: {
    textColor: "text-red-800",
    bgColor: "bg-red-50",
    borderColor: "border-red-200",
    label: "Urgent",
  },
  [StatusEnum.PASSED]: {
    textColor: "text-gray-600",
    bgColor: "bg-gray-50",
    borderColor: "border-gray-200",
    label: "Passed",
  },
};

export default function DeadlineStatus({
  label,
  isoDate,
  today,
  additionalInfo,
}: DeadlineStatusProps) {
  const status = getDeadlineStatus(isoDate, today);
  const relativeLabel = getDeadlineLabel(isoDate, today);
  const config = statusConfig[status];

  return (
    <div
      className={`flex items-start justify-between p-3 rounded-lg border ${config.bgColor} ${config.borderColor}`}
    >
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-2 flex-wrap">
          <span className={`text-sm font-semibold ${config.textColor}`}>
            {label}
          </span>
          <span
            className={`text-xs px-2 py-0.5 rounded-full font-medium ${config.bgColor} ${config.textColor} border ${config.borderColor}`}
          >
            {config.label}
          </span>
        </div>
        {isoDate && (
          <p className={`text-sm mt-0.5 ${config.textColor}`}>
            {formatDate(isoDate)}
          </p>
        )}
        {!isoDate && (
          <p className={`text-sm mt-0.5 ${config.textColor}`}>Not available</p>
        )}
        {additionalInfo && (
          <p className="text-xs text-gray-500 mt-0.5">{additionalInfo}</p>
        )}
      </div>
      <span
        className={`text-sm font-medium ml-3 whitespace-nowrap ${config.textColor}`}
      >
        {relativeLabel}
      </span>
    </div>
  );
}

"use client";

import { useState, useRef } from "react";

interface PromptOutputProps {
  promptText: string;
}

export default function PromptOutput({ promptText }: PromptOutputProps) {
  const [copied, setCopied] = useState(false);
  const [showFallback, setShowFallback] = useState(false);
  const textAreaRef = useRef<HTMLTextAreaElement>(null);

  async function handleCopy() {
    if (navigator.clipboard && navigator.clipboard.writeText) {
      try {
        await navigator.clipboard.writeText(promptText);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
        return;
      } catch {
        // Fall through to fallback
      }
    }
    // Fallback: select the text in the textarea
    if (textAreaRef.current) {
      textAreaRef.current.select();
      setShowFallback(true);
    }
  }

  return (
    <section
      className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden"
      aria-label="Customized ballot research prompt"
    >
      <div className="px-6 py-4 border-b border-gray-100 bg-gray-50">
        <h2 className="text-lg font-bold text-gray-900">
          Your Customized Ballot Research Prompt
        </h2>
        <p className="text-sm text-gray-600 mt-1">
          Copy this prompt and paste it as your first message in any AI chatbot
        </p>
      </div>

      <div className="p-6 space-y-4">
        {/* Instructions */}
        <div className="flex flex-col sm:flex-row gap-3 items-start sm:items-center justify-between">
          <div className="text-sm text-gray-600">
            <strong>How to use:</strong> Copy below → open any free AI chatbot →
            paste as your first message
          </div>
          <div className="flex items-center gap-2">
            <button
              data-testid="copy-button"
              onClick={handleCopy}
              className="flex items-center gap-2 px-5 py-2.5 bg-blue-600 hover:bg-blue-700 text-white text-sm font-semibold rounded-xl transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 min-h-[44px] min-w-[44px]"
              aria-label="Copy prompt to clipboard"
            >
              {copied ? (
                <>
                  <svg
                    className="w-4 h-4"
                    fill="none"
                    stroke="currentColor"
                    viewBox="0 0 24 24"
                    aria-hidden="true"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth={2}
                      d="M5 13l4 4L19 7"
                    />
                  </svg>
                  Copied!
                </>
              ) : (
                <>
                  <svg
                    className="w-4 h-4"
                    fill="none"
                    stroke="currentColor"
                    viewBox="0 0 24 24"
                    aria-hidden="true"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth={2}
                      d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z"
                    />
                  </svg>
                  Copy to Clipboard
                </>
              )}
            </button>
            {copied && (
              <span
                data-testid="copy-confirmation"
                role="status"
                aria-live="polite"
                className="text-sm text-green-700 font-medium"
              >
                ✓ Copied to clipboard!
              </span>
            )}
          </div>
        </div>

        {showFallback && (
          <div
            role="alert"
            aria-live="polite"
            className="text-sm text-amber-700 bg-amber-50 border border-amber-200 rounded-lg p-3"
          >
            Clipboard not available. The text is selected — press{" "}
            <kbd className="px-1.5 py-0.5 bg-amber-100 rounded text-xs font-mono">
              Ctrl+C
            </kbd>{" "}
            /{" "}
            <kbd className="px-1.5 py-0.5 bg-amber-100 rounded text-xs font-mono">
              Cmd+C
            </kbd>{" "}
            to copy.
          </div>
        )}

        {/* Prompt text area */}
        <div
          data-testid="prompt-output"
          className="relative"
          role="region"
          aria-label="Full ballot research prompt text"
        >
          <textarea
            ref={textAreaRef}
            readOnly
            value={promptText}
            rows={20}
            className="w-full p-4 text-sm font-mono bg-gray-50 border border-gray-200 rounded-xl resize-none focus:outline-none focus:ring-2 focus:ring-blue-500 text-gray-800 leading-relaxed"
            aria-label="Ballot research prompt — read only, use copy button above"
            aria-readonly="true"
          />
        </div>
      </div>
    </section>
  );
}

"use client";

export default function ShareButton() {
  function handleShare() {
    if (navigator.share) {
      navigator.share({
        title: "Voter Choice — AI Ballot Research",
        text: "Free AI ballot research tool — enter your zip code and get a personalized prompt for any AI chatbot.",
        url: window.location.href,
      });
    } else {
      navigator.clipboard.writeText(window.location.href).catch(() => {});
    }
  }

  return (
    <button
      onClick={handleShare}
      className="text-blue-600 hover:text-blue-800 font-medium underline underline-offset-2 min-h-[44px] flex items-center"
    >
      Share this tool
    </button>
  );
}

"use client";

import { useState, FormEvent, ChangeEvent } from "react";

interface ZipFormProps {
  onSubmit: (zipCode: string) => void;
  isLoading?: boolean;
}

export default function ZipForm({ onSubmit, isLoading = false }: ZipFormProps) {
  const [rawValue, setRawValue] = useState("");
  const [error, setError] = useState<string | null>(null);

  // Derive display value: only digits, max 5 chars
  const zipCode = rawValue.replace(/\D/g, "").slice(0, 5);

  function validate(raw: string): string | null {
    const trimmed = raw.trim();
    if (!trimmed) {
      return "Please enter a zip code";
    }
    // If the raw input contained non-digit characters or is wrong length
    if (!/^\d{5}$/.test(trimmed)) {
      return "Please enter a valid 5-digit zip code";
    }
    return null;
  }

  function handleSubmit(e: FormEvent<HTMLFormElement>) {
    e.preventDefault();
    // Validate against the raw value so non-numeric attempts are caught
    const validationError = validate(rawValue);
    if (validationError) {
      setError(validationError);
      return;
    }
    setError(null);
    onSubmit(zipCode);
  }

  function handleChange(e: ChangeEvent<HTMLInputElement>) {
    setRawValue(e.target.value);
    if (error) {
      setError(null);
    }
  }

  return (
    <form onSubmit={handleSubmit} noValidate className="w-full">
      <div className="flex flex-col sm:flex-row gap-3">
        <div className="flex-1">
          <label
            htmlFor="zip-code-input"
            className="block text-sm font-medium text-gray-700 mb-1.5"
          >
            Your zip code
          </label>
          <input
            id="zip-code-input"
            type="text"
            inputMode="numeric"
            pattern="[0-9]{5}"
            maxLength={10}
            data-testid="zip-input"
            value={rawValue}
            onChange={handleChange}
            placeholder="e.g. 73301"
            aria-label="5-digit US zip code"
            aria-describedby={error ? "zip-error-msg" : undefined}
            aria-invalid={error ? "true" : "false"}
            className={`w-full px-4 py-3 text-lg border-2 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 transition-colors min-h-[48px]
              ${
                error
                  ? "border-red-400 focus:border-red-400 focus:ring-red-300"
                  : "border-gray-300 focus:border-blue-500"
              }`}
            disabled={isLoading}
          />
          {error && (
            <p
              id="zip-error-msg"
              data-testid="zip-error"
              role="alert"
              aria-live="polite"
              className="mt-2 text-sm text-red-600 flex items-center gap-1.5"
            >
              <svg
                className="w-4 h-4 flex-shrink-0"
                fill="currentColor"
                viewBox="0 0 20 20"
                aria-hidden="true"
              >
                <path
                  fillRule="evenodd"
                  d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z"
                  clipRule="evenodd"
                />
              </svg>
              {error}
            </p>
          )}
        </div>
        <div className="sm:self-end">
          <button
            type="submit"
            data-testid="zip-submit"
            disabled={isLoading}
            className="w-full sm:w-auto px-8 py-3 bg-blue-600 hover:bg-blue-700 text-white font-semibold rounded-xl transition-colors focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 min-h-[48px] min-w-[44px] disabled:opacity-60 disabled:cursor-not-allowed"
          >
            {isLoading ? (
              <span className="flex items-center gap-2">
                <svg
                  className="w-4 h-4 animate-spin"
                  fill="none"
                  viewBox="0 0 24 24"
                  aria-hidden="true"
                >
                  <circle
                    className="opacity-25"
                    cx="12"
                    cy="12"
                    r="10"
                    stroke="currentColor"
                    strokeWidth="4"
                  />
                  <path
                    className="opacity-75"
                    fill="currentColor"
                    d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"
                  />
                </svg>
                Looking up...
              </span>
            ) : (
              "Look up my ballot"
            )}
          </button>
        </div>
      </div>
    </form>
  );
}

import { describe, it, expect } from "vitest";
import { buildContextBlock, buildPrompt } from "../promptBuilder";
import { getStateData } from "../stateData";
import { findNextElection } from "../stateData";

const TODAY = new Date(2026, 4, 11); // May 11, 2026

describe("buildContextBlock", () => {
  it("includes state name in context block", () => {
    const stateData = getStateData("TX")!;
    const election = findNextElection(stateData.elections, TODAY);
    const context = buildContextBlock(stateData, "73301", election);
    expect(context).toContain("Texas");
    expect(context).toContain("73301");
  });

  it("includes zip code in context block", () => {
    const stateData = getStateData("CA")!;
    const election = findNextElection(stateData.elections, TODAY);
    const context = buildContextBlock(stateData, "90210", election);
    expect(context).toContain("90210");
  });

  it("includes election name when election exists", () => {
    const stateData = getStateData("TX")!;
    const election = findNextElection(stateData.elections, TODAY);
    const context = buildContextBlock(stateData, "73301", election);
    if (election) {
      expect(context).toContain(election.name);
    }
  });

  it("includes registration deadline info", () => {
    const stateData = getStateData("TX")!;
    const election = findNextElection(stateData.elections, TODAY);
    const context = buildContextBlock(stateData, "73301", election);
    expect(context).toMatch(/registration/i);
  });

  it("includes sample ballot link", () => {
    const stateData = getStateData("TX")!;
    const election = findNextElection(stateData.elections, TODAY);
    const context = buildContextBlock(stateData, "73301", election);
    expect(context).toContain(stateData.resources.sampleBallotLookup);
  });

  it("includes county election office link", () => {
    const stateData = getStateData("TX")!;
    const election = findNextElection(stateData.elections, TODAY);
    const context = buildContextBlock(stateData, "73301", election);
    expect(context).toContain(stateData.resources.countyElectionLookup);
  });

  it("handles null election gracefully", () => {
    const stateData = getStateData("TX")!;
    const context = buildContextBlock(stateData, "73301", null);
    expect(context).toContain("Texas");
    expect(context).toMatch(/no upcoming election/i);
  });

  it("includes 'Help me with my ballot' call to action", () => {
    const stateData = getStateData("TX")!;
    const election = findNextElection(stateData.elections, TODAY);
    const context = buildContextBlock(stateData, "73301", election);
    expect(context).toContain("Help me with my ballot");
  });
});

describe("buildPrompt", () => {
  it("starts with the main prompt text", () => {
    const stateData = getStateData("TX")!;
    const election = findNextElection(stateData.elections, TODAY);
    const prompt = buildPrompt(stateData, "73301", election);
    expect(prompt).toContain("nonpartisan civic research assistant");
  });

  it("contains the context block after the main prompt", () => {
    const stateData = getStateData("TX")!;
    const election = findNextElection(stateData.elections, TODAY);
    const prompt = buildPrompt(stateData, "73301", election);
    expect(prompt).toContain("Texas");
    expect(prompt).toContain("73301");
    // Context block should come after the main prompt
    const mainPromptIdx = prompt.indexOf("nonpartisan civic research");
    const contextIdx = prompt.indexOf("I'm voting in");
    expect(contextIdx).toBeGreaterThan(mainPromptIdx);
  });

  it("builds California prompt correctly", () => {
    const stateData = getStateData("CA")!;
    const election = findNextElection(stateData.elections, TODAY);
    const prompt = buildPrompt(stateData, "90210", election);
    expect(prompt).toContain("California");
    expect(prompt).toContain("90210");
  });
});

import { describe, it, expect } from "vitest";
import {
  getStateCodesForZip,
  getStateData,
  findNextElection,
} from "../stateData";
import { Election } from "../types";

describe("getStateCodesForZip", () => {
  it("returns Texas for 73301", () => {
    expect(getStateCodesForZip("73301")).toEqual(["TX"]);
  });

  it("returns California for 90210", () => {
    expect(getStateCodesForZip("90210")).toEqual(["CA"]);
  });

  it("returns New Hampshire for 03031", () => {
    expect(getStateCodesForZip("03031")).toEqual(["NH"]);
  });

  it("returns multiple states for multi-state zip 86515", () => {
    const codes = getStateCodesForZip("86515");
    expect(codes).toContain("AZ");
    expect(codes).toContain("NM");
    expect(codes.length).toBe(2);
  });

  it("returns empty array for unknown zip", () => {
    expect(getStateCodesForZip("00000")).toEqual([]);
  });
});

describe("getStateData", () => {
  it("loads Texas state data", () => {
    const data = getStateData("TX");
    expect(data).not.toBeNull();
    expect(data?.stateName).toBe("Texas");
    expect(data?.stateCode).toBe("TX");
  });

  it("loads California state data", () => {
    const data = getStateData("CA");
    expect(data).not.toBeNull();
    expect(data?.stateName).toBe("California");
  });

  it("loads New Hampshire state data", () => {
    const data = getStateData("NH");
    expect(data).not.toBeNull();
    expect(data?.stateName).toBe("New Hampshire");
  });

  it("returns null for unknown state", () => {
    expect(getStateData("ZZ")).toBeNull();
  });
});

describe("findNextElection", () => {
  const elections: Election[] = [
    {
      id: "past",
      name: "Past Election",
      date: "2026-03-03",
      type: "primary",
      isPrimary: true,
      primaryType: "open",
    },
    {
      id: "upcoming",
      name: "Upcoming Election",
      date: "2026-11-03",
      type: "general",
      isPrimary: false,
      primaryType: null,
    },
    {
      id: "runoff",
      name: "Runoff Election",
      date: "2026-05-26",
      type: "runoff",
      isPrimary: false,
      primaryType: null,
    },
  ];

  const TODAY = new Date(2026, 4, 11); // May 11, 2026

  it("returns the next upcoming election", () => {
    const result = findNextElection(elections, TODAY);
    expect(result?.id).toBe("runoff");
    expect(result?.date).toBe("2026-05-26");
  });

  it("returns null when no upcoming elections", () => {
    const pastElections: Election[] = [
      {
        id: "old",
        name: "Old Election",
        date: "2025-11-03",
        type: "general",
        isPrimary: false,
        primaryType: null,
      },
    ];
    const result = findNextElection(pastElections, TODAY);
    expect(result).toBeNull();
  });

  it("includes election on same day as today", () => {
    const todayElections: Election[] = [
      {
        id: "today",
        name: "Today's Election",
        date: "2026-05-11",
        type: "primary",
        isPrimary: true,
        primaryType: "open",
      },
    ];
    const result = findNextElection(todayElections, TODAY);
    expect(result?.id).toBe("today");
  });

  it("returns null for empty elections array", () => {
    expect(findNextElection([], TODAY)).toBeNull();
  });
});

import { DeadlineStatus } from "./types";

/**
 * Calculate the number of days remaining until a deadline.
 * Negative values indicate the deadline has passed.
 */
export function getDaysRemaining(isoDate: string, today: Date): number {
  const deadline = new Date(isoDate + "T00:00:00");
  const todayMidnight = new Date(
    today.getFullYear(),
    today.getMonth(),
    today.getDate(),
  );
  const diffMs = deadline.getTime() - todayMidnight.getTime();
  return Math.floor(diffMs / (1000 * 60 * 60 * 24));
}

/**
 * Get the visual status for a registration deadline.
 * - GREEN: > 14 days remaining
 * - YELLOW: 1-14 days remaining
 * - RED: 0-3 days remaining (≤3 days)
 * - PASSED: deadline has passed (negative days)
 */
export function getDeadlineStatus(
  isoDate: string | null,
  today: Date,
): DeadlineStatus {
  if (!isoDate) return DeadlineStatus.PASSED;
  const days = getDaysRemaining(isoDate, today);
  if (days < 0) return DeadlineStatus.PASSED;
  if (days <= 3) return DeadlineStatus.RED;
  if (days <= 14) return DeadlineStatus.YELLOW;
  return DeadlineStatus.GREEN;
}

/**
 * Format a relative deadline label for display.
 */
export function getDeadlineLabel(isoDate: string | null, today: Date): string {
  if (!isoDate) return "Not available";
  const days = getDaysRemaining(isoDate, today);
  if (days < 0) return "Passed";
  if (days === 0) return "Today — Last Day";
  if (days === 1) return "1 day left";
  return `${days} days left`;
}

/**
 * Format an ISO date for display (e.g. "March 3, 2026").
 */
export function formatDate(isoDate: string): string {
  const [year, month, day] = isoDate.split("-").map(Number);
  const date = new Date(year, month - 1, day);
  return date.toLocaleDateString("en-US", {
    year: "numeric",
    month: "long",
    day: "numeric",
  });
}

/**
 * Check if all registration deadlines have passed.
 */
export function allDeadlinesPassed(
  deadlines: (string | null)[],
  today: Date,
): boolean {
  const validDeadlines = deadlines.filter((d) => d !== null) as string[];
  if (validDeadlines.length === 0) return true;
  return validDeadlines.every((d) => getDaysRemaining(d, today) < 0);
}

import { StateData, ZipLookup, Election } from "./types";
import zipToStateData from "../data/zip-to-state.json";
import txData from "../data/states/TX.json";
import caData from "../data/states/CA.json";
import nhData from "../data/states/NH.json";

const zipToState: ZipLookup = zipToStateData as ZipLookup;

const stateDataMap: Record<string, StateData> = {
  TX: txData as StateData,
  CA: caData as StateData,
  NH: nhData as StateData,
};

/**
 * Look up state codes for a given zip code.
 * Returns an empty array if zip not found.
 */
export function getStateCodesForZip(zipCode: string): string[] {
  return zipToState[zipCode] ?? [];
}

/**
 * Load state data by state code.
 * Returns null if state not in dataset.
 */
export function getStateData(stateCode: string): StateData | null {
  return stateDataMap[stateCode] ?? null;
}

/**
 * Find the next upcoming election on or after today.
 * Returns null if no upcoming elections exist.
 */
export function findNextElection(
  elections: Election[],
  today: Date,
): Election | null {
  const todayStr = today.toISOString().split("T")[0];
  const upcoming = elections.filter((e) => e.date >= todayStr);
  if (upcoming.length === 0) return null;
  // Sort by date ascending and return first
  upcoming.sort((a, b) => a.date.localeCompare(b.date));
  return upcoming[0];
}
